"use strict";

/**
 * Isolate the context in an IIFE
 *
 * @param object $ jQuery object
 * @param object Drupal Drupal object
 * @param window window Current window object
 * @param document document Current document object
 */
(function ($, Drupal, once) {
  /**
   * Main script for the current theme
   */
  Drupal.behaviors.yukon = {
    attach: function attach() {
      jQuery('select#edit-event-year-filter').change(function () {
        var year = jQuery(this).val();
        var url = "/docroot/year_month_change/".concat(year);
        jQuery.ajax({
          type: 'POST',
          url: url,
          data: {
            year: year
          }
        }).done(function (data) {
          if (data[0]) {
            var $country = jQuery('select#edit-event-month-filter');
            $country.empty();
            var keys = Object.keys(data[0]);
            $country.append('<option value="All">- Any -</option>');

            for (var i = 0; i < keys.length; i++) {
              var key = keys[i];
              $country.append("<option value=\"".concat(keys[i], "\">").concat(data[0][key], "</option>"));
            }
          }
        });
      });
      $('.yukon-accordion__expand').click(function (e) {
        e.preventDefault();
        $('.accordion .collapse').addClass('show');
        $('.panel-title a[data-toggle="collapse"]').find('.title-icon svg').addClass('fa-square-minus fa-square-plus');
      });
      $('.yukon-accordion__collapse').click(function (e) {
        e.preventDefault();
        $('.accordion .collapse').removeClass('show');
        $('.panel-title a[data-toggle="collapse"]').find('.title-icon svg').addClass('fa-square-plus fa-square-minus');
      });
      $('a.add_new_comment').click(function (e) {
        e.preventDefault();
        $('.comment-blog-comments-form ').show();
        $('a.close_comment').show();
        $('a.add_new_comment').hide();
      });
      $('a.close_comment').click(function (e) {
        e.preventDefault();
        $('.comment-blog-comments-form ').hide();
        $('a.close_comment').hide();
        $('a.add_new_comment').show();
      });
      $('.page-node-type-department .accordion .accordion-item:first-child .accordion-collapse').addClass('show');
      jQuery(document).ready(function () {
        if (!$('#block-yukonca-glider-views-block-related-tasks-block-1 .views-field-field-related-tasks .field-content div').hasClass('item-list')) {
          $('#block-yukonca-glider-views-block-related-tasks-block-1').hide();
        }

        function filterOpener() {
          var ele = $('aside .filters h2.title');

          if ($(window).width() < 768) {
            ele.removeClass('toggled');
            $('aside .filters form').hide();
            ele.off('click.filterOpener').on('click.filterOpener', function () {
              $(this).toggleClass('toggled');
              $('aside .filters form').stop(true).slideToggle();
            });
          } else {
            ele.off('click.filterOpener').removeClass('toggled');
            $('aside .filters form').show();
          }
        }

        filterOpener();
        $(window).resize(function () {
          filterOpener();
        });
        var $sidebar = jQuery('.layout-sidebar-first, .layout-sidebar-second');

        if ($sidebar.length) {
          var sidebarOffsetTop = $sidebar.offset().top;
          jQuery(window).on('scroll resize', function () {
            if (jQuery(window).width() <= 768) {
              if (jQuery(window).scrollTop() >= sidebarOffsetTop) {
                $sidebar.addClass('sticky-active');
              } else {
                $sidebar.removeClass('sticky-active');
              }
            } else {
              $sidebar.removeClass('sticky-active');
              filterOpener();
            }
          });
        }

        $('[data-once="bef-auto-submit"] .js-form-item .js-form-item [type="checkbox"]').change(function () {
          $('html, body').animate({
            scrollTop: $('#block-views-block-find-a-campground, #block-views-block-block-backcountry-campgrounds').offset().top
          }, 1000);
        });
        var tables = document.querySelectorAll('table:not(.table-wrapper > table)');
        tables.forEach(function (table) {
          var wrapper = document.createElement('div');
          wrapper.className = 'table-wrapper';
          table.parentNode.insertBefore(wrapper, table);
          wrapper.appendChild(table);
        });
      });
    }
  };
  Drupal.behaviors.quickExit = {
    attach: function attach(context) {
      once('jsBehaviour', '.quick-exit-btn', context).forEach(function (element) {
        element.addEventListener('click', function (event) {
          event.preventDefault();
          var newUrl = element.getAttribute('href');
          var previousUrl = drupalSettings.quick_exit.previous;
          var backUrl = drupalSettings.quick_exit.back;
          window.history.replaceState({}, '', backUrl);
          window.open(newUrl, '_blank');
          window.location.href = previousUrl;
        });
      });
    }
  };
  Drupal.behaviors.clickToCall = {
    attach: function attach(context) {
      once('clickToCall', '.click-to-call-button', context).forEach(function (button) {
        button.addEventListener('click', function (event) {
          event.preventDefault();
          var container = button.closest('.click-to-call-floating-button');
          var telephone = container ? container.dataset.telephone : null;

          if (telephone) {
            // Open telephone app with the number.
            window.location.href = "tel:".concat(telephone);
          }
        });
      });
    }
  };
  Drupal.behaviors.eventOccurrenceFilter = {
    attach: function attach(context) {
      once('eventOccurrenceFilter', '.event-occurrences', context).forEach(function (fieldset) {
        var hash = window.location.hash;

        if (!hash || !/^#occurrence-\d+$/.test(hash)) {
          return;
        }

        var targetId = hash.slice(1);
        fieldset.querySelectorAll('.event-occurrence').forEach(function (el) {
          if (el.id !== targetId) {
            el.hidden = true;
          }
        });
      });
    }
  };
})(jQuery, Drupal, window.once);